nta.declaration:
		// -----------------------------------------------------------
// 1. Variáveis e Clocks Globais
// -----------------------------------------------------------
clock t;
int score = 10;

// Constantes do Sistema
const int NUM_EDGES = 9;
const int NUM_HYPEREDGES = 6;
const int NUM_IDS = 9;

// -----------------------------------------------------------
// 2. Definições de Estrutura Reativa
// -----------------------------------------------------------
typedef struct {
		int id;		// ID da ação
		bool stat; // Estado (1=ativo, 0=inativo)
} Edge;

typedef struct {
		int id;		// ID da ação gatilho
		bool type; // Tipo de efeito (1=ativa, 0=desativa)
		bool stat; // Estado da regra
		bool is_edge_target; // 1 se alvo é Aresta, 0 se Regra
		int trg_index;			 // Índice no array alvo
} Hyperedge;

// -----------------------------------------------------------
// 3. Inicialização dos Arrays
// -----------------------------------------------------------
Edge A[NUM_EDGES] = {
		{ 0, 1 } /* Idx 0: Watch_Init->Watch_View:beginView */,
		{ 1, 1 } /* Idx 1: Watch_React->Feed:dontLike */,
		{ 2, 1 } /* Idx 2: Watch_View->Watch_React:dwellTime */,
		{ 3, 1 } /* Idx 3: Watch_React->Watch_React:like */,
		{ 4, 0 } /* Idx 4: Watch_React->Feed:refresh */,
		{ 5, 1 } /* Idx 5: Watch_View->Feed:timeout */,
		{ 6, 1 } /* Idx 6: Feed->Watch_Init:watch */,
		{ 7, 1 } /* Idx 7: List->Watch_Init:watch2 */,
		{ 8, 0 } /* Idx 8: Feed->List:watchLike */
};
Hyperedge L[NUM_HYPEREDGES] = {
		{ 3, 1, 1, 1, 4 } /* Rule 'lr' */,
		{ 3, 1, 1, 1, 8 } /* Rule 'lw' */,
		{ 2, 1, 1, 1, 4 } /* Rule 'dr' */,
		{ 2, 1, 1, 1, 8 } /* Rule 'dwll' */,
		{ 1, 0, 1, 1, 8 } /* Rule 'dww' */,
		{ 1, 0, 1, 1, 4 } /* Rule 'dref' */
};

// -----------------------------------------------------------
// 4. Lógica de Atualização Reativa
// -----------------------------------------------------------
void update_hyperedges_by_id(int edge_id) {
		int i;
		for (i = 0; i < NUM_HYPEREDGES; i++) {
				if (L[i].id == edge_id && L[i].stat) { 
						if (L[i].is_edge_target) {
								A[L[i].trg_index].stat = L[i].type;
						} else {
								L[L[i].trg_index].stat = L[i].type;
						}
				}
		}
}

// -----------------------------------------------------------
// 5. Funções de Dados (Geradas)
// -----------------------------------------------------------
void update_data_0() {
	t = 0;
}
void update_data_1() {
	if (score >= 10) {
	score = score - 10;
}
	t = 0;
}
void update_data_2() {
	t = 0;
}
void update_data_3() {
	if (score <= 90) {
	score = score + 10;
}
	t = 0;
}
void update_data_4() {
	t = 0;
}
void update_data_5() {
	if (score >= 5) {
	score = score - 5;
}
	t = 0;
}
void update_data_6() {
	t = 0;
}
void update_data_7() {
	t = 0;
}
void update_data_8() {
	t = 0;
}
